@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    if 'user_id' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
    user = User.query.get(session['user_id'])
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    data = request.get_json()
    if not data or 'mfa_secret' not in data:
        return jsonify({'error': 'MFA secret required'}), 400
    
    user.mfa_enabled = True
    user.mfa_secret = data['mfa_secret']
    db.session.commit()
    
    return jsonify({'message': 'MFA enabled successfully'})

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    if 'user_id' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
